import sys
from functools import lru_cache

def solve():
    input_data = sys.stdin.read().split()
    n, x = int(input_data[0]), int(input_data[1])
    MOD = 998244353

    # Precompute binomial coefficients
    maxn = n + 5
    C = [[0] * maxn for _ in range(maxn)]
    C[0][0] = 1
    for i in range(1, maxn):
        C[i][0] = 1
        for j in range(1, maxn):
            C[i][j] = (C[i-1][j-1] + C[i-1][j]) % MOD

    # DP: state = (c, k) where c = current threshold, k = current number of alive heroes
    # dp[(c, k)] = weighted count of ways to assign heroes dying in previous phases
    # We want sum over all terminal states (k'=0)

    # Use iterative DP
    # dp[c][k] = number of ordered partial assignments

    # c can go up to x+1, k from 0 to n
    dp = {}
    dp[(1, n)] = 1

    ans = 0

    # BFS/iterative over states
    from collections import deque
    queue = deque()
    queue.append((1, n, 1))  # (c, k, weight) -- use dp dict instead

    # Iterative DP with dictionary
    current = {(1, n): 1}

    while current:
        next_states = {}
        for (c, k), ways in current.items():
            if k == 0:
                ans = (ans + ways) % MOD
                continue
            # c_{t+1} = c + k - 1
            c_next = c + k - 1
            # L = number of valid values in [c, c+k-2] intersected with [1,x]
            # range [c, c+k-2], length k-1
            if c > x:
                L = 0
            else:
                L = max(0, min(c + k - 2, x) - c + 1)

            # Choose k_next in {0, 2, 3, ..., k}, k_next != 1
            for k_next in range(0, k + 1):
                if k_next == 1:
                    continue
                if k_next > k:
                    continue
                n_dying = k - k_next

                # Check feasibility
                if n_dying > 0 and L == 0:
                    continue
                if k_next > 0 and c_next > x:
                    continue

                # Contribution: C(k, n_dying) * L^n_dying
                if n_dying == 0:
                    factor = 1
                else:
                    factor = C[k][n_dying] * pow(L, n_dying, MOD) % MOD

                new_ways = ways * factor % MOD

                key = (c_next, k_next)
                if key not in next_states:
                    next_states[key] = 0
                next_states[key] = (next_states[key] + new_ways) % MOD

        # Handle k=0 states that were added
        current = {}
        for (c, k), ways in next_states.items():
            if k == 0:
                ans = (ans + ways) % MOD
            else:
                if (c, k) not in current:
                    current[(c, k)] = 0
                current[(c, k)] = (current[(c, k)] + ways) % MOD

    print(ans % MOD)

